const readline = require('readline');
const rl = readline.createInterface({ input: process.stdin });

rl.on('line', (line) => {
    const stack = [];
    const matching = { ')': '(', '}': '{', ']': '[' };
    let valid = true;

    for (const char of line) {
        if (char === '(' || char === '{' || char === '[') {
            stack.push(char);
        } else {
            if (stack.length === 0 || stack.pop() !== matching[char]) {
                valid = false;
                break;
            }
        }
    }

    console.log(valid && stack.length === 0);
    rl.close();
});
